// Normalize a Gmail message (simplified output) into a clean row.
const m = $input.first().json || {};
const rawFrom = m.From || m.from || (m.headers && (m.headers.from || m.headers.From)) || '';
const mt = String(rawFrom).match(/<([^>]+)>/);
const from_email = String(mt ? mt[1] : rawFrom).trim().toLowerCase();
const from_name = String(rawFrom).replace(/<[^>]+>/, '').replace(/"/g, '').trim() || from_email;
const subject = m.Subject || m.subject || (m.headers && (m.headers.subject || m.headers.Subject)) || '';
const body = m.text || m.textPlain || m.snippet || (m.textHtml ? String(m.textHtml).replace(/<[^>]+>/g, ' ') : '') || '';
const atts = [];
const rawAtts = m.attachments || (m.payload && m.payload.attachments) || [];
if (Array.isArray(rawAtts)) for (const a of rawAtts) atts.push(a.fileName || a.filename || a.name || 'attachment');
else if (rawAtts && typeof rawAtts === 'object') for (const k of Object.keys(rawAtts)) atts.push(rawAtts[k].fileName || k);
return [{ json: {
  message_id: m.id || m.messageId || '',
  thread_id: m.threadId || '',
  from_email,
  from_name,
  subject: String(subject).slice(0, 500),
  body: String(body).replace(/\s+/g, ' ').trim().slice(0, 4000),
  attachments: atts,
  has_attachment: atts.length > 0
}}];

