// Merge classification into the Supabase row.
let cls = {};
try { cls = JSON.parse($json.choices[0].message.content); } catch (e) {}
const src = $('Normalize email').item.json;
return [{ json: {
  message_id: src.message_id,
  thread_id: src.thread_id || null,
  from_email: src.from_email,
  from_name: src.from_name,
  subject: src.subject,
  body: src.body,
  intent: cls.intent || 'other',
  products: cls.products || [],
  doc_type: cls.doc_type && cls.doc_type !== 'null' ? cls.doc_type : (src.has_attachment ? 'other' : null),
  has_attachment: src.has_attachment,
  attachments: src.attachments || [],
  summary: cls.summary || null,
  received_at: $now.toISO()
}}];
